package org.example.cpm.math;
import java.util.Arrays;
public record Mat4d(double[] values){ public Mat4d{if(values==null||values.length!=16)throw new IllegalArgumentException("matrix length"); values=values.clone();for(double v:values)if(!Double.isFinite(v))throw new IllegalArgumentException("non-finite matrix");} public static Mat4d identity(){double[]a=new double[16];for(int i=0;i<4;i++)a[i*4+i]=1;return new Mat4d(a);} public static Mat4d translation(Vec3d p){var a=identity().valuesCopy();a[3]=p.x();a[7]=p.y();a[11]=p.z();return new Mat4d(a);} public Mat4d multiply(Mat4d b){double[]o=new double[16];for(int r=0;r<4;r++)for(int c=0;c<4;c++)for(int k=0;k<4;k++)o[r*4+c]+=values[r*4+k]*b.values[k*4+c];return new Mat4d(o);} public Vec3d transformPoint(Vec3d p){double[]v={p.x(),p.y(),p.z(),1};return new Vec3d(values[0]*v[0]+values[1]*v[1]+values[2]*v[2]+values[3],values[4]*v[0]+values[5]*v[1]+values[6]*v[2]+values[7],values[8]*v[0]+values[9]*v[1]+values[10]*v[2]+values[11]);} public Vec3d transformDirection(Vec3d p){return new Vec3d(values[0]*p.x()+values[1]*p.y()+values[2]*p.z(),values[4]*p.x()+values[5]*p.y()+values[6]*p.z(),values[8]*p.x()+values[9]*p.y()+values[10]*p.z());} public double[] valuesCopy(){return values.clone();} }
